onSubmit.body:
// Calculate derived fields on submit
var allSections = window.__ALL_SECTIONS_DATA__;
var section1Data = allSections?.['melting'] || {};

// Total Energy Consumed = Final KWH - Initial KWH
var initialKwh = Number(section1Data['melting__initial_kwh_reading'] || 0);
var finalKwh = Number(e.data.post_melting__final_kwh_reading || 0);
e.data.post_melting__total_energy_consumed = finalKwh - initialKwh;

// Furnace Running Hours = Final Reading Time - Initial Reading Time (in hours)
var initialReadingTime = section1Data['melting__reading_time'];
var finalReadingTime = e.data.post_melting__final_reading_time;
if (initialReadingTime && finalReadingTime) {
    var t1 = new Date(initialReadingTime);
    var t2 = new Date(finalReadingTime);
    var diffMs = t2.getTime() - t1.getTime();
    e.data.post_melting__furnace_running_hours = Math.round((diffMs / (1000 * 60 * 60)) * 100) / 100;
} else {
    e.data.post_melting__furnace_running_hours = 0;
}

// Energy per MT = Total Energy Consumed / (Total Scrap Weight in MT)
var totalScrapWeight = Number(section1Data['melting__total_scrap_weight'] || 0);
var totalScrapMT = totalScrapWeight / 1000;
if (totalScrapMT > 0) {
    e.data.post_melting__energy_per_mt = Math.round((e.data.post_melting__total_energy_consumed / totalScrapMT) * 100) / 100;
} else {
    e.data.post_melting__energy_per_mt = 0;
}

console.log("Derived values:", {
    total_energy: e.data.post_melting__total_energy_consumed,
    running_hours: e.data.post_melting__furnace_running_hours,
    energy_per_mt: e.data.post_melting__energy_per_mt
});

console.log("Form Submitted");

